import{_ as o,o as t,c as r,ag as i}from"./chunks/framework.DXGyWiRo.js";const d=JSON.parse('{"title":"Desktop Voice Logging","description":"","frontmatter":{},"headers":[],"relativePath":"voice-logging/desktop.md","filePath":"voice-logging/desktop.md"}'),s={name:"voice-logging/desktop.md"};function a(n,e,p,c,l,h){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="desktop-voice-logging" tabindex="-1">Desktop Voice Logging <a class="header-anchor" href="#desktop-voice-logging" aria-label="Permalink to &quot;Desktop Voice Logging&quot;">​</a></h1><p>Desktop voice logging uses the browser&#39;s built-in Web Speech API. It works without any keyboard setup.</p><h2 id="how-to-use" tabindex="-1">How to Use <a class="header-anchor" href="#how-to-use" aria-label="Permalink to &quot;How to Use&quot;">​</a></h2><ol><li>Open the Voice Logger from the Game Hub or Practice Hub</li><li>Click the <strong>microphone button</strong></li><li>Speak your play description clearly</li><li>The recording stops automatically after a brief pause</li><li>Review the confirmation card and tap <strong>Confirm and Save</strong></li></ol><h2 id="tips-for-desktop" tabindex="-1">Tips for Desktop <a class="header-anchor" href="#tips-for-desktop" aria-label="Permalink to &quot;Tips for Desktop&quot;">​</a></h2><p><strong>Speak at a natural pace</strong> — the browser&#39;s speech recognition performs better with normal speaking speed than slow, over-enunciated speech.</p><p><strong>Pause between plays</strong> — the auto-stop detects silence. After you finish speaking wait a moment for the recording to stop and the AI to process.</p><p><strong>Timeout behavior</strong> — if you pause too long mid-description the recording may stop early. If this happens your partial description may not parse correctly. Tap <strong>Try Again</strong> and speak the complete play description without long pauses.</p><p><strong>Background noise</strong> — desktop microphones pick up more ambient noise than phone microphones held closer to the mouth. Work in a reasonably quiet environment or use a headset microphone.</p><h2 id="browser-microphone-permission" tabindex="-1">Browser Microphone Permission <a class="header-anchor" href="#browser-microphone-permission" aria-label="Permalink to &quot;Browser Microphone Permission&quot;">​</a></h2><p>The first time you use voice logging your browser will request microphone access. Click <strong>Allow</strong>. If you accidentally denied it:</p><ul><li><strong>Chrome:</strong> Click the lock icon in the address bar → Site settings → Microphone → Allow</li><li><strong>Edge:</strong> Same process via the lock icon</li><li><strong>Safari (Mac):</strong> System Preferences → Security &amp; Privacy → Microphone → check the browser</li></ul>',12)])])}const u=o(s,[["render",a]]);export{d as __pageData,u as default};
